from flask import Flask, request
from werkzeug.security import generate_password_hash, check_password_hash
import jwt
import datetime
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = 'super-secret-key'  # Replace with your secret key

users = {
    "admin": generate_password_hash("password")
}

def require_appkey(view_function):
    @wraps(view_function)
    def decorated_function(*args, **kwargs):
        with open('api_keys.txt', 'r') as api_file:
            api_keys = [line.strip() for line in api_file]
        if 'x-api-key' not in request.headers or request.headers['x-api-key'] not in api_keys:
            return {"message": "Authentication Failure. Invalid API Key."}, 403
        return view_function(*args, **kwargs)
    return decorated_function

@app.route('/login', methods=['POST'])
def login():
    user = request.form.get('username')
    password = request.form.get('password')
    if not users.get(user):
        return {"message": "User Not Found."}, 403
    if check_password_hash(users[user], password) is False:
        return {"message": "Password Incorrect"}, 403
    
    token = jwt.encode({"username": user, 'exp': datetime.datetime.utcnow() + datetime.timedelta(hours=12)}, app.config['SECRET_KEY'])
    return {"token": token}, 200

@app.route('/protected', methods=['GET'])
@require_appkey
def protected():
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return {"message": "No Authorization header"}, 403
    bearer, token = auth_header.split()
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'])
    except jwt.exceptions.ExpiredSignatureError:
        return {"message": "Token has expired"}, 403
    except jwt.exceptions.DecodeError:
        return {"message": "Invalid token"}, 403
    
    return {"message": f"Hello, {payload['username']}!"}, 200